B2 = 0.011443

def poly_act(x):
    return 0.125 * x * x + 0.5 * x + 0.25

@compile(scheme='ckks')
def traffic_policy(*features):
    h = []
    for row, b in zip(W1, B1):
        acc = b
        for w, x in zip(row, features):
            acc = acc + w * x
        h.append(poly_act(acc))
    out = B2
    for w, x in zip(W2, h):
        out = out + w * x
    return out
